import{_ as a,o as s,c as r,ae as i}from"./chunks/framework.Czhw_PXq.js";const t="/images/hub_realms.png",o="/images/hub_realms_add.png",n="/images/hub_realms_details.png",l="/images/hub_user.png",m="/images/hub_user_details.png",c="/images/hub_user_roles.png",d="/images/hub_user_add.png",p="/images/hub_robots.png",h="/images/hub_robots_details.png",u="/images/hub_robots_roles.png",g="/images/hub_robots_permissions.png",_="/images/hub_robots_add.png",b="/images/permissions.png",A=JSON.parse('{"title":"Realms","description":"","frontmatter":{},"headers":[],"relativePath":"guide/user/realms.md","filePath":"guide/user/realms.md"}'),v={name:"guide/user/realms.md"};function R(f,e,y,P,q,k){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="realms" tabindex="-1">Realms <a class="header-anchor" href="#realms" aria-label="Permalink to &quot;Realms&quot;">​</a></h1><p>Realms are organizational containers in PrivateAIM Hub that group identity providers, robots, users, roles, and nodes. They are managed through Authup and enforced across all Hub services.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><img src="'+t+'" alt="Realms overview"></p><p>Each realm is an isolated organizational unit. Resources created within a realm (projects, analyses, nodes) are scoped to that realm unless accessed by a <strong>master realm</strong> administrator.</p><ul><li>The <strong>master realm</strong> has global access — its members can manage all resources across realms</li><li>Non-master realm users can only access resources within their own realm</li></ul><h2 id="managing-realms" tabindex="-1">Managing Realms <a class="header-anchor" href="#managing-realms" aria-label="Permalink to &quot;Managing Realms&quot;">​</a></h2><h3 id="creating-a-realm" tabindex="-1">Creating a Realm <a class="header-anchor" href="#creating-a-realm" aria-label="Permalink to &quot;Creating a Realm&quot;">​</a></h3><p><img src="'+o+'" alt="Add realm"></p><h3 id="realm-details" tabindex="-1">Realm Details <a class="header-anchor" href="#realm-details" aria-label="Permalink to &quot;Realm Details&quot;">​</a></h3><p><img src="'+n+`" alt="Realm details"></p><h2 id="realm-scoping" tabindex="-1">Realm Scoping <a class="header-anchor" href="#realm-scoping" aria-label="Permalink to &quot;Realm Scoping&quot;">​</a></h2><p>All realm-scoped entities carry a <code>realm_id</code> column. Access is enforced by the <code>isRealmResourceWritable()</code> helper in every entity service:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Master realm member  →  can read/write all resources</span></span>
<span class="line"><span>Other realm member   →  can only read/write own realm&#39;s resources</span></span></code></pre></div><p>This applies to all CRUD operations — creating, reading, updating, and deleting entities.</p><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><p><img src="`+l+'" alt="Users overview"></p><p>Users are human accounts within a realm. Administrators can manage users, assign roles, and view details.</p><p><img src="'+m+'" alt="User details"></p><p><img src="'+c+'" alt="User roles"></p><p><img src="'+d+'" alt="Add user"></p><h2 id="robots" tabindex="-1">Robots <a class="header-anchor" href="#robots" aria-label="Permalink to &quot;Robots&quot;">​</a></h2><p>Robots are API pseudo-users for automation. They belong to a realm and are assigned roles and permissions just like human users.</p><p><img src="'+p+'" alt="Robots overview"></p><p>Use robots for:</p><ul><li>Automated pipelines that interact with the Hub API</li><li>Service-to-service communication</li><li>CI/CD integrations</li></ul><p><img src="'+h+'" alt="Robot details"></p><p><img src="'+u+'" alt="Robot roles"></p><p><img src="'+g+'" alt="Robot permissions"></p><p><img src="'+_+'" alt="Add robot"></p><h2 id="roles-permissions" tabindex="-1">Roles &amp; Permissions <a class="header-anchor" href="#roles-permissions" aria-label="Permalink to &quot;Roles &amp; Permissions&quot;">​</a></h2><p>Hub uses role-based access control (RBAC) via Authup:</p><ul><li><strong>Roles</strong> group related permissions and are assigned to users or robots within a realm</li><li><strong>Permissions</strong> are pre-defined actions (e.g., <code>node_create</code>, <code>analysis_update</code>) checked at the service layer</li><li>Two-phase permission model: <code>preCheck</code> (fast fail) then <code>check</code> (with policy attributes)</li></ul><p><img src="'+b+'" alt="Permissions"></p><h2 id="identity-providers" tabindex="-1">Identity Providers <a class="header-anchor" href="#identity-providers" aria-label="Permalink to &quot;Identity Providers&quot;">​</a></h2><p>Each realm can configure OIDC identity providers for federated authentication. Users authenticate through their realm&#39;s identity provider, and Authup maps the external identity to a Hub user.</p>',36)])])}const x=a(v,[["render",R]]);export{A as __pageData,x as default};
